import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/installer-screen.Db0E_BrK.js";import{t as a}from"./chunks/launcher-screen.B4Y3DSWp.js";const o=JSON.parse(`{"title":"在 Windows 上安装 Fabric","description":"在 Windows 上安装 Fabric 的逐步指南。","frontmatter":{"title":"在 Windows 上安装 Fabric","description":"在 Windows 上安装 Fabric 的逐步指南。","authors":["Benonardo","ezfe","IMB11","modmuss50"],"next":false,"files":[]},"headers":[],"relativePath":"zh_cn/players/installing-fabric/windows.md","filePath":"translated/zh_cn/players/installing-fabric/windows.md","lastUpdated":1770561656000}`);var s={name:`zh_cn/players/installing-fabric/windows.md`};function c(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">在 Windows 上安装 Fabric <a class="header-anchor" href="#h1" aria-label="Permalink to “在 Windows 上安装 Fabric”">​</a></h1><h2 id="1-download-the-fabric-installer" tabindex="-1">1. 下载 Fabric 安装程序 <a class="header-anchor" href="#1-download-the-fabric-installer" aria-label="Permalink to “1. 下载 Fabric 安装程序”">​</a></h2><p>从 <a href="https://fabricmc.net/use/" target="_blank" rel="noreferrer">Fabric 网站</a>下载 Fabric 安装程序的 <code>.exe</code> 版本，单击 <code>Download for Windows</code>。</p><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>Windows 的 <code>.exe</code> 版本不需要安装 Java，因为它使用随官方 Minecraft 启动器捆绑的 Java。</p></div><h2 id="2-run-the-fabric-installer" tabindex="-1">2. 运行 Fabric 安装器 <a class="header-anchor" href="#2-run-the-fabric-installer" aria-label="Permalink to “2. 运行 Fabric 安装器”">​</a></h2><p>请先关闭 Minecraft 和 Minecraft 启动器，然后再运行安装程序。</p><p>打开安装程序后，你应该会看到类似这样的画面：</p><p><img src="/assets/players/installing-fabric/installer-screen.png" alt="高亮显示“安装”的 Fabric 安装程序" loading="lazy"></p><p>选择你想要的 Minecraft 版本，然后单击 <code>Install</code>。 请确保勾选 <code>Create Profile</code>。</p><h2 id="3-finish-setup" tabindex="-1">3. 完成安装 <a class="header-anchor" href="#3-finish-setup" aria-label="Permalink to “3. 完成安装”">​</a></h2><p>安装完成后，打开 Minecraft 启动器。 然后从版本下拉菜单中选择 Fabric 配置文件，然后单击“开始游戏”。</p><p><img src="/assets/players/installing-fabric/launcher-screen.png" alt="已选择 Fabric 配置文件的 Minecraft 启动器" loading="lazy"></p><p>现在你可以给游戏添加模组了。 详情请参阅<a href="./../finding-mods">寻找可信的模组</a>指南。</p><p>如果遇到问题，可随时在 <a href="https://discord.fabricmc.net/" target="_blank" rel="noreferrer">Fabric Discord</a> 的 <code>#player-support</code> 频道中寻求帮助。</p>`,14)]])}var l=r(s,[[`render`,c]]);export{o as __pageData,l as default};